import{_ as l,o as i,c as t,ag as r}from"./chunks/framework.DEs8X8sU.js";const c=JSON.parse('{"title":"Part 1 — 毎日の営業（開店〜閉店）超詳細版","description":"","frontmatter":{"title":"Part 1 — 毎日の営業（開店〜閉店）超詳細版","audience":"全スタッフ（特に新人アルバイト向け）","prerequisite":"Part 0（POSLA を使う前の準備）を読み終わっていること","last_updated":"2026-04-19T00:00:00.000Z"},"headers":[],"relativePath":"operations/part1-daily-operations.md","filePath":"operations/part1-daily-operations.md"}'),o={name:"operations/part1-daily-operations.md"};function n(s,a,e,h,d,g){return i(),t("div",null,[...a[0]||(a[0]=[r(`<h1 id="part-1-—-毎日の営業-開店〜閉店" tabindex="-1">Part 1 — 毎日の営業（開店〜閉店） <a class="header-anchor" href="#part-1-—-毎日の営業-開店〜閉店" aria-label="Permalink to &quot;Part 1 — 毎日の営業（開店〜閉店）&quot;">​</a></h1><p>このページは、<strong>朝お店を開ける時から夜閉める時まで</strong>、POSLA を使って 1 日を運営する流れを、<strong>指の動き 1 つずつ</strong> 順番に書いています。</p><div class="tip custom-block"><p class="custom-block-title">このページの使い方</p><ul><li><strong>役割ごとに読むページが違います</strong>: <ul><li><strong>キッチンスタッフ（厨房）</strong>: 1-1-1、1-3、1-7、1-9 を中心に</li><li><strong>ホールスタッフ（フロア）</strong>: 1-2、1-4、1-6 を中心に</li><li><strong>レジ担当</strong>: 1-1-2、1-5、1-9-1 を中心に</li><li><strong>店長・オーナー</strong>: 全部読んで把握してください</li></ul></li><li><strong>初めての日は全部を上から読む</strong> と流れが分かります</li><li>分からない言葉は Part 0 の「0-7. 画面の見方」と「0-8. ロール」を見直してください</li></ul></div><hr><h2 id="_1-1-開店準備-営業時間の-15〜30-分前" tabindex="-1">1-1. 開店準備（営業時間の 15〜30 分前） <a class="header-anchor" href="#_1-1-開店準備-営業時間の-15〜30-分前" aria-label="Permalink to &quot;1-1. 開店準備（営業時間の 15〜30 分前）&quot;">​</a></h2><p>お店の扉を開ける前に、POSLA の機材を起動してログインします。</p><h3 id="_1-1-1-kds-キッチンディスプレイ-の電源を入れてログインする" tabindex="-1">1-1-1. KDS（キッチンディスプレイ）の電源を入れてログインする <a class="header-anchor" href="#_1-1-1-kds-キッチンディスプレイ-の電源を入れてログインする" aria-label="Permalink to &quot;1-1-1. KDS（キッチンディスプレイ）の電源を入れてログインする&quot;">​</a></h3><p><strong>対象者</strong>: キッチンスタッフ / 店長</p><h4 id="必要なもの" tabindex="-1">必要なもの <a class="header-anchor" href="#必要なもの" aria-label="Permalink to &quot;必要なもの&quot;">​</a></h4><ul><li>キッチンに設置されているタブレット（iPad 推奨、10 インチ以上）</li><li>Wi-Fi が繋がっていること</li><li>オーナー/店長から教えてもらったキッチン用ログイン情報（例: ユーザー名 <code>kds-shibuya-01</code>）</li></ul><h4 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>キッチンの壁やカウンターに設置されているタブレットを確認</li><li>タブレットの <strong>電源ボタン</strong>（本体側面または上部の細長いボタン）を 1 秒押す</li><li>画面が明るくなる</li><li>ロック画面（時計だけの画面）が出たら、上にスワイプ（指でなぞる）して解除</li><li>ホーム画面で <strong>「Chrome」</strong> アイコン（赤・黄・緑・青の丸）をタップして起動</li><li>画面上部の <strong>アドレスバー</strong>（細長い白い枠）をタップ</li><li>次の URL を半角で入力（または事前にブックマーク済みなら選ぶだけ）:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://eat.posla.jp/public/kds/index.html</span></span></code></pre></div></li><li>キーボードの <strong>「開く」</strong> または <strong>「Enter」</strong> をタップ</li><li>「管理画面ログイン」と書かれた画面が開く</li><li><strong>ユーザー名</strong> 欄にキッチン用ログイン名（例: <code>kds-shibuya-01</code>）を入力</li><li><strong>パスワード</strong> 欄にパスワードを入力</li><li>青い <strong>【ログイン】</strong> ボタンをタップ</li></ol><h4 id="ログイン成功後の動作" tabindex="-1">ログイン成功後の動作 <a class="header-anchor" href="#ログイン成功後の動作" aria-label="Permalink to &quot;ログイン成功後の動作&quot;">​</a></h4><ul><li><strong>複数店舗所属の場合</strong>: 店舗選択のオーバーレイ（小さなウィンドウ）が表示される → 該当店舗をタップ</li><li><strong>黒い画面「音声を有効にする」というオーバーレイが表示</strong>: <ul><li><strong>【タップして開始】</strong>（黒いボタン）を必ず 1 回タップ</li><li>これをしないと <strong>新規注文の通知音が鳴りません</strong></li><li>iOS/Safari の制約で、音声を鳴らすには 1 回ユーザー操作が必要</li></ul></li><li>タップ後、KDS カンバン画面（3 つの縦カラムに分かれた画面）が表示される</li></ul><h4 id="kds-画面の見方-基本" tabindex="-1">KDS 画面の見方（基本） <a class="header-anchor" href="#kds-画面の見方-基本" aria-label="Permalink to &quot;KDS 画面の見方（基本）&quot;">​</a></h4><p>画面が以下の 3 つの縦カラムに分かれています:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┬──────────┬──────────┐</span></span>
<span class="line"><span>│  受付    │ 調理中   │ 提供待ち │</span></span>
<span class="line"><span>│ (pending)│(preparing)│(ready)  │</span></span>
<span class="line"><span>│          │          │          │</span></span>
<span class="line"><span>│[注文 1]  │[注文 3]  │[注文 5]  │</span></span>
<span class="line"><span>│[注文 2]  │[注文 4]  │          │</span></span>
<span class="line"><span>│          │          │          │</span></span>
<span class="line"><span>└──────────┴──────────┴──────────┘</span></span></code></pre></div><ul><li><strong>受付</strong>: お客様が注文送信したばかりで、まだ調理を始めていない注文</li><li><strong>調理中</strong>: 「調理開始」ボタンを押して調理している注文</li><li><strong>提供待ち</strong>: 調理完了（「完成」ボタンを押した）して、ホールが取りに来るのを待っている注文</li></ul><p>各カラムの上に数字（件数）が表示されます。カラムに注文カードが並びます。</p><h4 id="カラムの色分け" tabindex="-1">カラムの色分け <a class="header-anchor" href="#カラムの色分け" aria-label="Permalink to &quot;カラムの色分け&quot;">​</a></h4><ul><li><strong>受付</strong>: 左枠オレンジ（<code>#e65100</code>）</li><li><strong>調理中</strong>: 左枠黄色（<code>#f9a825</code>）</li><li><strong>提供待ち</strong>: 左枠緑（<code>#2e7d32</code>）</li></ul><h4 id="時間経過の色警告" tabindex="-1">時間経過の色警告 <a class="header-anchor" href="#時間経過の色警告" aria-label="Permalink to &quot;時間経過の色警告&quot;">​</a></h4><ul><li><strong>注文から 10 分経過</strong>: カードが警告色（オレンジ背景）に変わる</li><li><strong>注文から 20 分経過</strong>: カードが危険色（赤背景）に変わり、点滅する</li></ul><h4 id="ログインが失敗した場合" tabindex="-1">ログインが失敗した場合 <a class="header-anchor" href="#ログインが失敗した場合" aria-label="Permalink to &quot;ログインが失敗した場合&quot;">​</a></h4><table tabindex="0"><thead><tr><th>画面表示</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>「ユーザー名またはパスワードが正しくありません」</td><td>入力ミス</td><td>大文字小文字、0 と O、1 と l の見間違い確認</td></tr><tr><td>「このアカウントは無効化されています」</td><td>店長がアカウントを停止した</td><td>店長に連絡</td></tr><tr><td>「通信エラーが発生しました」</td><td>Wi-Fi が切れている</td><td>Wi-Fi アイコンを確認、必要ならルーター再起動</td></tr><tr><td>画面真っ白</td><td>ブラウザの問題</td><td>Chrome を閉じて再起動、またはキャッシュクリア</td></tr><tr><td>「店舗外からのアクセス」赤いオーバーレイ</td><td>GPS チェックで店外判定</td><td>GPS を許可し、店内にいることを確認</td></tr></tbody></table><hr><h3 id="_1-1-2-posレジの電源を入れてログインする" tabindex="-1">1-1-2. POSレジの電源を入れてログインする <a class="header-anchor" href="#_1-1-2-posレジの電源を入れてログインする" aria-label="Permalink to &quot;1-1-2. POSレジの電源を入れてログインする&quot;">​</a></h3><p><strong>対象者</strong>: レジ担当 / 店長</p><h4 id="必要なもの-1" tabindex="-1">必要なもの <a class="header-anchor" href="#必要なもの-1" aria-label="Permalink to &quot;必要なもの&quot;">​</a></h4><ul><li>レジカウンターに設置されているタブレット</li><li>Stripe Reader S700（カード決済を受ける場合、コンセントに接続されていること）</li><li>レジ用ログイン情報（例: <code>register-shibuya-01</code>）</li></ul><h4 id="手順-1" tabindex="-1">手順 <a class="header-anchor" href="#手順-1" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>レジタブレットの電源を入れる</li><li>Chrome を起動</li><li>以下の URL を開く（ブックマーク推奨）:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://eat.posla.jp/public/kds/cashier.html</span></span></code></pre></div></li><li>レジ用ユーザー名・パスワードでログイン</li><li>複数店舗なら店舗を選択</li><li>「音声を有効にする」オーバーレイで <strong>【タップして開始】</strong> をタップ</li><li>POSレジ画面が表示される</li></ol><h4 id="posレジ画面の見方" tabindex="-1">POSレジ画面の見方 <a class="header-anchor" href="#posレジ画面の見方" aria-label="Permalink to &quot;POSレジ画面の見方&quot;">​</a></h4><p>画面が 2 つの縦カラムに分かれています:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────┬────────────────────┐</span></span>
<span class="line"><span>│ 会計待ちテーブル │   会計画面          │</span></span>
<span class="line"><span>│ (左カラム)      │   (右カラム)        │</span></span>
<span class="line"><span>│                │                     │</span></span>
<span class="line"><span>│ [T01 ¥3,400]   │  テーブル未選択時は │</span></span>
<span class="line"><span>│ [T02 ¥5,800]   │  「左から会計する   │</span></span>
<span class="line"><span>│ [T03 ¥2,200]   │  テーブルをタップ」 │</span></span>
<span class="line"><span>│                │                     │</span></span>
<span class="line"><span>│ 本日売上合計   │                     │</span></span>
<span class="line"><span>│ ¥48,500        │                     │</span></span>
<span class="line"><span>└────────────────┴────────────────────┘</span></span></code></pre></div><h4 id="ヘッダー" tabindex="-1">ヘッダー <a class="header-anchor" href="#ヘッダー" aria-label="Permalink to &quot;ヘッダー&quot;">​</a></h4><ul><li><strong>POSレジ</strong> タイトル</li><li><strong>選択中の店舗名</strong></li><li><strong>Stripe Terminal 接続状態</strong>（S700 が繋がっているかの表示）</li><li><strong>スタッフ名</strong>（誰が今レジを担当しているか）</li><li><strong>時計</strong></li><li><strong>📋 取引履歴</strong>: 過去の会計を見る</li><li><strong>💰 レジ開閉</strong>: レジ開け・レジ締め</li><li><strong>🔊 音声</strong>: レジ操作音の ON/OFF</li></ul><h4 id="stripe-terminal-カードリーダー-接続確認" tabindex="-1">Stripe Terminal（カードリーダー）接続確認 <a class="header-anchor" href="#stripe-terminal-カードリーダー-接続確認" aria-label="Permalink to &quot;Stripe Terminal（カードリーダー）接続確認&quot;">​</a></h4><ol><li>Stripe Reader S700 の電源を入れる（本体の電源ボタン長押し）</li><li>S700 がお店の Wi-Fi に繋がっていることを確認（画面に Wi-Fi アイコンが表示される）</li><li>POSレジ画面の右上に <strong>「Terminal 接続中」</strong> または <strong>「S700-xxxx 接続中」</strong> と緑色で表示されていれば OK</li><li>「未接続」と赤色表示の場合は、画面右上の Stripe 設定から <strong>【再検出】</strong> を押す</li></ol><hr><h3 id="_1-1-3-ハンディ端末の準備" tabindex="-1">1-1-3. ハンディ端末の準備 <a class="header-anchor" href="#_1-1-3-ハンディ端末の準備" aria-label="Permalink to &quot;1-1-3. ハンディ端末の準備&quot;">​</a></h3><p><strong>対象者</strong>: ホールスタッフ / 店長</p><h4 id="必要なもの-2" tabindex="-1">必要なもの <a class="header-anchor" href="#必要なもの-2" aria-label="Permalink to &quot;必要なもの&quot;">​</a></h4><ul><li>ハンディ用タブレット/スマホ（店舗備品）</li><li>首掛けストラップまたは腰ホルスター</li></ul><h4 id="手順-2" tabindex="-1">手順 <a class="header-anchor" href="#手順-2" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>ハンディ端末の電源を入れる</li><li>Chrome を起動</li><li>以下の URL を開く:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://eat.posla.jp/public/handy/index.html</span></span></code></pre></div></li><li>ハンディ用アカウント（例: <code>handy-shibuya-01</code>）でログイン</li><li>店舗選択</li><li>GPS オーバーレイが出たら <strong>【位置情報を許可】</strong> をタップ</li><li>ハンディ画面が表示される</li></ol><h4 id="ハンディ画面の上部タブ" tabindex="-1">ハンディ画面の上部タブ <a class="header-anchor" href="#ハンディ画面の上部タブ" aria-label="Permalink to &quot;ハンディ画面の上部タブ&quot;">​</a></h4><p>画面上部に以下の 5 つのタブが横並びに表示されます:</p><table tabindex="0"><thead><tr><th>タブ名</th><th>用途</th></tr></thead><tbody><tr><td><strong>店内注文</strong></td><td>店内席のお客様からの注文を入力</td></tr><tr><td><strong>テイクアウト</strong></td><td>テイクアウト注文を入力</td></tr><tr><td><strong>テーブル状況</strong></td><td>全テーブルの使用状況（着席中、空席、予約済みなど）を確認</td></tr><tr><td><strong>📅 予約</strong></td><td>当日の予約一覧、着席操作、QR 開放</td></tr><tr><td><strong>注文履歴</strong></td><td>過去の注文を見る・編集する</td></tr></tbody></table><hr><h3 id="_1-1-4-stripe-reader-s700-カードリーダー-の接続確認" tabindex="-1">1-1-4. Stripe Reader S700（カードリーダー）の接続確認 <a class="header-anchor" href="#_1-1-4-stripe-reader-s700-カードリーダー-の接続確認" aria-label="Permalink to &quot;1-1-4. Stripe Reader S700（カードリーダー）の接続確認&quot;">​</a></h3><p>Stripe Reader S700 は <strong>お店の Wi-Fi に繋がって初めて使える</strong> カードリーダーです。</p><ol><li>S700 本体の <strong>電源ボタン</strong>（本体上部）を 2 秒長押し</li><li>画面に Stripe ロゴが表示される</li><li>初回設定で Wi-Fi に接続してあれば、自動で Wi-Fi に繋がる</li><li>画面に <strong>「Stripe アプリ」</strong> の画面が表示されれば準備完了</li><li>POSレジ画面の右上で <strong>「Terminal 接続中」</strong> 表示を確認</li></ol><h4 id="wi-fi-設定がまだのとき-初回のみ" tabindex="-1">Wi-Fi 設定がまだのとき（初回のみ） <a class="header-anchor" href="#wi-fi-設定がまだのとき-初回のみ" aria-label="Permalink to &quot;Wi-Fi 設定がまだのとき（初回のみ）&quot;">​</a></h4><ol><li>S700 画面で <strong>【設定】</strong>（歯車アイコン）をタップ</li><li><strong>【ネットワーク設定】</strong> を選ぶ</li><li><strong>【Wi-Fi 追加】</strong> で SSID を選択</li><li>Wi-Fi パスワードを入力</li><li>接続完了</li></ol><h4 id="s700-が反応しないとき" tabindex="-1">S700 が反応しないとき <a class="header-anchor" href="#s700-が反応しないとき" aria-label="Permalink to &quot;S700 が反応しないとき&quot;">​</a></h4><ul><li>バッテリー切れ → 付属の USB-C ケーブルでコンセントに繋ぐ</li><li>Wi-Fi 未接続 → 上記 Wi-Fi 設定をやり直す</li><li>Stripe アカウント未設定 → オーナーに確認（Stripe Connect 連携済みか）</li></ul><hr><h3 id="_1-1-5-レシートプリンタの接続確認" tabindex="-1">1-1-5. レシートプリンタの接続確認 <a class="header-anchor" href="#_1-1-5-レシートプリンタの接続確認" aria-label="Permalink to &quot;1-1-5. レシートプリンタの接続確認&quot;">​</a></h3><p>お店でプリンタを導入している場合、レシート・キッチン伝票が紙で印刷されます。</p><h4 id="手順-3" tabindex="-1">手順 <a class="header-anchor" href="#手順-3" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>プリンタの電源を入れる（本体の電源ボタン）</li><li><strong>緑色のランプ</strong> が点灯することを確認</li><li>POSLA 管理画面の「店舗設定」→「プリンタ設定」で設定済みかチェック</li><li><strong>【🖨 テスト印刷】</strong> ボタンでテスト用紙が出てくるか確認</li></ol><h4 id="紙がなくなったら" tabindex="-1">紙がなくなったら <a class="header-anchor" href="#紙がなくなったら" aria-label="Permalink to &quot;紙がなくなったら&quot;">​</a></h4><ol><li>プリンタのカバーを開ける（本体の爪を押して開く）</li><li>新しいロール紙をセット</li><li>紙の先端を少し出してカバーを閉める</li><li>プリンタ側面のランプが緑に戻ることを確認</li></ol><hr><h3 id="_1-1-6-レジを開ける-開店作業" tabindex="-1">1-1-6. レジを開ける（開店作業） <a class="header-anchor" href="#_1-1-6-レジを開ける-開店作業" aria-label="Permalink to &quot;1-1-6. レジを開ける（開店作業）&quot;">​</a></h3><p>レジの準備金（つり銭用の硬貨・紙幣）を登録して、1 日の営業をスタートする操作です。</p><div class="warning custom-block"><p class="custom-block-title">開店前の準備（CB1d、2026-04-19 追加）</p><p>レジ開け操作には <strong>担当スタッフの PIN 入力が必須</strong> です。<strong>マネージャーも例外なく</strong>、操作前に下記を済ませておいてください。</p><ol><li>自分の <strong>個人スタッフアカウント</strong>で管理画面にログイン</li><li><strong>【🟢 出勤】</strong> で出勤打刻（GPS 許可）</li><li>レジ担当 PIN が未設定なら、店長に依頼するか自分で設定</li></ol><p>これをやらないと「PIN が一致しないか、対象スタッフが出勤中ではありません」エラーで開けられません。</p></div><h4 id="手順-4" tabindex="-1">手順 <a class="header-anchor" href="#手順-4" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>POSレジ画面の右上 <strong>【💰 レジ開閉】</strong> ボタンをタップ</li><li><strong>【レジを開ける】</strong> というパネルが開く</li><li>「開始時在高（レジに入れる準備金）」欄に金額を入力 <ul><li>例: ¥10,000（千円札 5 枚 + 500 円玉 10 枚）</li><li>お店によって決まった金額があるはず（店長に確認）</li></ul></li><li><strong>【開く】</strong> ボタンをタップ</li><li><strong>担当スタッフ PIN 入力モーダル</strong>が表示される（CB1d、2026-04-19 追加）</li><li>自分の 4〜8 桁 PIN をテンキーで入力 → <strong>【確定】</strong></li><li>画面に「レジを開けました」と緑色のメッセージ</li><li>以降、売上が記録されていく</li></ol><div class="tip custom-block"><p class="custom-block-title">開店前の準備金の金額は店舗ルール次第</p><p>多くのお店で ¥10,000〜¥30,000 を準備金として入れています。店長に必ず確認してください。</p></div><h4 id="お釣り準備で「入金」する場合-cb1d-対応" tabindex="-1">お釣り準備で「入金」する場合（CB1d 対応） <a class="header-anchor" href="#お釣り準備で「入金」する場合-cb1d-対応" aria-label="Permalink to &quot;お釣り準備で「入金」する場合（CB1d 対応）&quot;">​</a></h4><p>営業中に両替してきた小銭をレジに足す等の「入金」も同じく PIN 必須です。</p><ol><li><strong>【💰 レジ開閉】</strong> → <strong>【入金】</strong> セクション</li><li>金額・メモ（例: 「両替 ¥10,000 → 千円札 10 枚」）を入力</li><li><strong>【入金】</strong> → <strong>PIN モーダル</strong> → 自分の PIN 入力 → 確定</li></ol><h4 id="営業中に「出金」する場合-cb1d、特に重要" tabindex="-1">営業中に「出金」する場合（CB1d、特に重要） <a class="header-anchor" href="#営業中に「出金」する場合-cb1d、特に重要" aria-label="Permalink to &quot;営業中に「出金」する場合（CB1d、特に重要）&quot;">​</a></h4><p>仕入れ代金の支払い・銀行入金等で現金をレジから出すときも PIN 必須です。<strong>出金は不正抑止のため最も厳しく追跡されます</strong>。誰が・いつ・いくら・何のために動かしたかが監査ログにすべて残ります。</p><ol><li><strong>【💰 レジ開閉】</strong> → <strong>【出金】</strong> セクション</li><li>金額・メモ（出金理由は必ず明確に: 「○○商店 仕入支払」「銀行集金」など）を入力</li><li><strong>【出金】</strong> → <strong>PIN モーダル</strong> → 自分の PIN 入力 → 確定</li></ol><hr><h2 id="_1-2-お客様が来たとき-ホール接客" tabindex="-1">1-2. お客様が来たとき（ホール接客） <a class="header-anchor" href="#_1-2-お客様が来たとき-ホール接客" aria-label="Permalink to &quot;1-2. お客様が来たとき（ホール接客）&quot;">​</a></h2><p><strong>対象者</strong>: ホールスタッフ</p><h3 id="_1-2-1-テーブルに案内する-空席確認" tabindex="-1">1-2-1. テーブルに案内する（空席確認） <a class="header-anchor" href="#_1-2-1-テーブルに案内する-空席確認" aria-label="Permalink to &quot;1-2-1. テーブルに案内する（空席確認）&quot;">​</a></h3><ol><li>ハンディ画面を開く</li><li><strong>【テーブル状況】</strong> タブをタップ</li><li>全テーブルの状況が色別のカードで表示される: <ul><li>🟢 緑: 空席</li><li>🟡 黄: 着席中（注文あり）</li><li>🔴 赤: 会計待ち</li><li>⚪ グレー: 無効化されたテーブル</li></ul></li><li>空席のテーブル（T03 など）をお客様に案内</li></ol><h3 id="_1-2-2-テーブル開放認証-📲-qr-開放ボタンの押し方" tabindex="-1">1-2-2. テーブル開放認証（📲 QR 開放ボタンの押し方） <a class="header-anchor" href="#_1-2-2-テーブル開放認証-📲-qr-開放ボタンの押し方" aria-label="Permalink to &quot;1-2-2. テーブル開放認証（📲 QR 開放ボタンの押し方）&quot;">​</a></h3><p>POSLA では <strong>スタッフが物理的にテーブルを「開放」した後でしかお客様が QR から注文できない仕組み</strong> を使っています（L-9 テーブル開放認証）。これにより <strong>店外から QR の写真を撮って遠隔注文される攻撃</strong> を防ぎます。</p><h4 id="手順-5" tabindex="-1">手順 <a class="header-anchor" href="#手順-5" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>ハンディ画面の <strong>【テーブル状況】</strong> タブを開く</li><li>お客様を案内したテーブル（T03）のカードを探す</li><li>カードの下部にある <strong>緑色の【📲 QR 開放（5 分）】</strong> ボタンをタップ</li><li>「開放しました」とメッセージ</li><li>そのテーブルは <strong>5 分間だけ</strong> お客様が QR から注文できる状態になる</li><li>お客様がテーブルの QR コードをスマホで読む</li><li>読んだ瞬間にテーブルセッションが確立して、4 時間（デフォルト）有効になる</li></ol><div class="tip custom-block"><p class="custom-block-title">5 分以内に誰も QR を読まなかった場合</p><p>再度 <strong>【📲 QR 開放】</strong> を押してください。過去に QR 開放したトークンは自動無効化されます。</p></div><h3 id="_1-2-3-お客様に-qr-コードの読み方を説明する" tabindex="-1">1-2-3. お客様に QR コードの読み方を説明する <a class="header-anchor" href="#_1-2-3-お客様に-qr-コードの読み方を説明する" aria-label="Permalink to &quot;1-2-3. お客様に QR コードの読み方を説明する&quot;">​</a></h3><p>お客様は自分のスマホで:</p><ol><li>スマホの <strong>カメラアプリ</strong> を起動（大体ホーム画面にアイコンがある）</li><li>テーブルに置かれた <strong>QR コード</strong>（紙）にカメラを向ける</li><li>カメラが QR を認識すると、画面上部に URL 通知が表示される</li><li>通知をタップ</li><li>POSLA のメニュー画面（セルフオーダー）が開く</li></ol><p>お客様のスマホに説明しないといけない場合の言い方:</p><ul><li>「カメラをこの QR に向けてください」</li><li>「画面の上の方に小さくリンクが出るので、それをタップしてください」</li></ul><h3 id="_1-2-4-ハンディで注文を入れる-スタッフがお客様の代わりに注文を取る場合" tabindex="-1">1-2-4. ハンディで注文を入れる（スタッフがお客様の代わりに注文を取る場合） <a class="header-anchor" href="#_1-2-4-ハンディで注文を入れる-スタッフがお客様の代わりに注文を取る場合" aria-label="Permalink to &quot;1-2-4. ハンディで注文を入れる（スタッフがお客様の代わりに注文を取る場合）&quot;">​</a></h3><p>セルフオーダーではなく、スタッフが注文を取る場合の手順です。</p><h4 id="手順-6" tabindex="-1">手順 <a class="header-anchor" href="#手順-6" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>ハンディの <strong>【店内注文】</strong> タブをタップ</li><li>画面上部の <strong>「テーブル」</strong> ドロップダウンから該当テーブル（T03 など）を選ぶ</li><li>下に表示されるメニュー一覧から注文された品をタップ</li><li>オプションがあるメニューならオプション選択モーダルが開く → 選んで【カートに追加】</li><li>画面下部の <strong>カートバー</strong> に選んだ品が追加される</li><li>数量を変更したい場合は <strong>+/−</strong> ボタン、削除なら <strong>🗑</strong> アイコン</li><li>メモ欄があれば「アレルギー: 卵抜き」「○○席」などを記入（最大 200 文字）</li><li>全品選び終えたら <strong>【注文送信】</strong> ボタン（画面右下の緑の大きなボタン）をタップ</li><li>確認ダイアログで <strong>【OK】</strong></li><li>送信完了 → キッチンの KDS 画面に自動で注文が流れる</li></ol><h4 id="注文送信の画面表示" tabindex="-1">注文送信の画面表示 <a class="header-anchor" href="#注文送信の画面表示" aria-label="Permalink to &quot;注文送信の画面表示&quot;">​</a></h4><ul><li>成功: 緑色の「注文を送信しました」トースト</li><li>失敗: 赤いエラーメッセージ</li></ul><hr><h2 id="_1-3-キッチン-厨房-での操作" tabindex="-1">1-3. キッチン（厨房）での操作 <a class="header-anchor" href="#_1-3-キッチン-厨房-での操作" aria-label="Permalink to &quot;1-3. キッチン（厨房）での操作&quot;">​</a></h2><p><strong>対象者</strong>: キッチンスタッフ / 店長</p><h3 id="_1-3-1-kds-画面で新規注文を確認" tabindex="-1">1-3-1. KDS 画面で新規注文を確認 <a class="header-anchor" href="#_1-3-1-kds-画面で新規注文を確認" aria-label="Permalink to &quot;1-3-1. KDS 画面で新規注文を確認&quot;">​</a></h3><ol><li>KDS 画面の <strong>左カラム「受付」</strong> を見る</li><li>新規注文が来ると <strong>ピコン音</strong> と共に、受付カラムに新しいカードが追加される</li><li>注文カードには以下が表示される: <ul><li>テーブル番号（例: T03）または顧客名（テイクアウト時）</li><li>経過時間（注文から何分経ったか）</li><li>メモ（アレルギー情報など）</li><li>品目一覧（メニュー名・個数・オプション）</li></ul></li></ol><h3 id="_1-3-2-注文を「調理開始」にする" tabindex="-1">1-3-2. 注文を「調理開始」にする <a class="header-anchor" href="#_1-3-2-注文を「調理開始」にする" aria-label="Permalink to &quot;1-3-2. 注文を「調理開始」にする&quot;">​</a></h3><p>調理を始める時の操作です。</p><h4 id="方法-a-注文全体を調理開始-簡単" tabindex="-1">方法 A: 注文全体を調理開始（簡単） <a class="header-anchor" href="#方法-a-注文全体を調理開始-簡単" aria-label="Permalink to &quot;方法 A: 注文全体を調理開始（簡単）&quot;">​</a></h4><ol><li>注文カードの下部の <strong>【全品調理開始】</strong> ボタンをタップ</li><li>注文カード全体が「調理中」カラムに移動</li><li>経過時間タイマーが継続</li></ol><h4 id="方法-b-品目ごとに調理開始-細かく管理したい場合" tabindex="-1">方法 B: 品目ごとに調理開始（細かく管理したい場合） <a class="header-anchor" href="#方法-b-品目ごとに調理開始-細かく管理したい場合" aria-label="Permalink to &quot;方法 B: 品目ごとに調理開始（細かく管理したい場合）&quot;">​</a></h4><ol><li>注文カード内の特定の品目の <strong>【調理開始】</strong> 小ボタンをタップ</li><li>その品目だけが緑（準備中）色に変わる</li><li>全品目が調理開始になると、注文全体が調理中カラムに移動</li></ol><h3 id="_1-3-3-調理が終わったら「提供待ち」にする" tabindex="-1">1-3-3. 調理が終わったら「提供待ち」にする <a class="header-anchor" href="#_1-3-3-調理が終わったら「提供待ち」にする" aria-label="Permalink to &quot;1-3-3. 調理が終わったら「提供待ち」にする&quot;">​</a></h3><p>1 品完成したら:</p><h4 id="方法-a-注文全体を完成" tabindex="-1">方法 A: 注文全体を完成 <a class="header-anchor" href="#方法-a-注文全体を完成" aria-label="Permalink to &quot;方法 A: 注文全体を完成&quot;">​</a></h4><ol><li>注文カードの下部の <strong>【全品完成】</strong> ボタン</li><li>注文全体が「提供待ち」カラムに移動</li><li><strong>同時に、ホール側のハンディ画面に「料理ができました」アラートが自動送信される</strong>（call_alerts の product_ready）</li></ol><h4 id="方法-b-品目ごとに完成" tabindex="-1">方法 B: 品目ごとに完成 <a class="header-anchor" href="#方法-b-品目ごとに完成" aria-label="Permalink to &quot;方法 B: 品目ごとに完成&quot;">​</a></h4><ol><li>注文カードの特定品目の <strong>【完成】</strong> 小ボタン</li><li>その品目だけ完成状態</li><li>全品目完成したら注文全体が提供待ちカラムへ移動</li></ol><h3 id="_1-3-4-音声コマンドで操作する方法" tabindex="-1">1-3-4. 音声コマンドで操作する方法 <a class="header-anchor" href="#_1-3-4-音声コマンドで操作する方法" aria-label="Permalink to &quot;1-3-4. 音声コマンドで操作する方法&quot;">​</a></h3><p>キッチンは両手が塞がっていることが多いので、<strong>声で KDS を操作</strong> できます。</p><h4 id="前提" tabindex="-1">前提 <a class="header-anchor" href="#前提" aria-label="Permalink to &quot;前提&quot;">​</a></h4><ul><li>Chrome ブラウザ（Safari は不可）</li><li>マイクが有効</li><li>初回の <strong>【タップして開始】</strong> で音声を有効化済み</li></ul><h4 id="基本コマンド" tabindex="-1">基本コマンド <a class="header-anchor" href="#基本コマンド" aria-label="Permalink to &quot;基本コマンド&quot;">​</a></h4><table tabindex="0"><thead><tr><th>言葉</th><th>動作</th></tr></thead><tbody><tr><td>「T01 調理開始」</td><td>T01 の注文を pending → preparing</td></tr><tr><td>「T01 完成」</td><td>T01 の注文を preparing → ready</td></tr><tr><td>「T01 提供」</td><td>T01 の注文を ready → served</td></tr><tr><td>「1番 調理開始」</td><td>同上（「T」なしでも可）</td></tr><tr><td>「テーブル 01 調理開始」</td><td>同上</td></tr></tbody></table><h4 id="品目単位コマンド" tabindex="-1">品目単位コマンド <a class="header-anchor" href="#品目単位コマンド" aria-label="Permalink to &quot;品目単位コマンド&quot;">​</a></h4><p>「T01 カツ丼 できた」のように、品目名を含めると特定の品目だけ完成にできます。</p><h4 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h4><ul><li><strong>造語はウェイクワードに使えません</strong> — 「POSLA！」のような呼び出し言葉は不要</li><li>騒音が多い厨房では誤認識する場合あり</li><li>音声が認識されないときは、画面の指ボタンで操作できるので安心してください</li></ul><hr><h2 id="_1-4-料理を提供する-ホール" tabindex="-1">1-4. 料理を提供する（ホール） <a class="header-anchor" href="#_1-4-料理を提供する-ホール" aria-label="Permalink to &quot;1-4. 料理を提供する（ホール）&quot;">​</a></h2><p><strong>対象者</strong>: ホールスタッフ</p><h3 id="_1-4-1-料理完成アラートの確認" tabindex="-1">1-4-1. 料理完成アラートの確認 <a class="header-anchor" href="#_1-4-1-料理完成アラートの確認" aria-label="Permalink to &quot;1-4-1. 料理完成アラートの確認&quot;">​</a></h3><ol><li>キッチンで料理が完成すると、ホールのハンディ画面に <strong>ピコン音</strong> と共にアラートが表示される</li><li>画面上部に <strong>「T03 カツ丼できました」</strong> のようなバナー</li><li>タップすると詳細が開く</li></ol><h3 id="_1-4-2-料理を運ぶ" tabindex="-1">1-4-2. 料理を運ぶ <a class="header-anchor" href="#_1-4-2-料理を運ぶ" aria-label="Permalink to &quot;1-4-2. 料理を運ぶ&quot;">​</a></h3><ol><li>キッチンに行って料理を受け取る</li><li>該当テーブルに運ぶ</li><li>ハンディ画面のアラートで <strong>【提供済み】</strong> をタップ</li><li>または KDS 画面の「提供待ち」カラムで、該当注文の <strong>【全品提供済み】</strong> をタップ</li><li>注文カードが消える（「完了」状態）</li></ol><h3 id="_1-4-3-テーブルの状態を確認" tabindex="-1">1-4-3. テーブルの状態を確認 <a class="header-anchor" href="#_1-4-3-テーブルの状態を確認" aria-label="Permalink to &quot;1-4-3. テーブルの状態を確認&quot;">​</a></h3><ul><li>ハンディ画面の <strong>【テーブル状況】</strong> タブでそのテーブルの状態を確認</li><li>着席中 → お客様がまだ食事中</li></ul><hr><h2 id="_1-5-お会計" tabindex="-1">1-5. お会計 <a class="header-anchor" href="#_1-5-お会計" aria-label="Permalink to &quot;1-5. お会計&quot;">​</a></h2><p><strong>対象者</strong>: レジ担当</p><p>お客様が食事を終えて会計をする時の操作です。POSレジ画面で行います。</p><h3 id="_1-5-0-担当スタッフ-pin-入力-2026-04-19-追加、毎回必要" tabindex="-1">1-5-0. 担当スタッフ PIN 入力（2026-04-19 追加、毎回必要） <a class="header-anchor" href="#_1-5-0-担当スタッフ-pin-入力-2026-04-19-追加、毎回必要" aria-label="Permalink to &quot;1-5-0. 担当スタッフ PIN 入力（2026-04-19 追加、毎回必要）&quot;">​</a></h3><p>会計確定時に <strong>担当スタッフの 4〜8 桁 PIN</strong> 入力が必要になりました（CP1 機能）。誰がレジを操作したかを正確に記録するため。</p><h4 id="必要な前提" tabindex="-1">必要な前提 <a class="header-anchor" href="#必要な前提" aria-label="Permalink to &quot;必要な前提&quot;">​</a></h4><ul><li>スタッフ各自が事前に <strong>PIN 設定済み</strong>（管理画面で店長が設定 or 自分で設定）</li><li>スタッフが朝、個人 staff アカウントで管理画面にログイン → <strong>出勤打刻</strong> している</li><li>（退勤打刻したスタッフの PIN は自動無効化される）</li></ul><h4 id="入力フロー" tabindex="-1">入力フロー <a class="header-anchor" href="#入力フロー" aria-label="Permalink to &quot;入力フロー&quot;">​</a></h4><ol><li>会計実行時、確認ダイアログで「OK」を押すと <strong>PIN 入力モーダル</strong> が表示</li><li>テンキーで自分の 4〜8 桁 PIN を入力</li><li><strong>【確定】</strong> ボタン</li><li>PIN 一致 → 会計実行・レシート発行</li><li>PIN 不一致 → 「PIN が一致しないか、対象スタッフが出勤中ではありません」エラー → 再入力</li></ol><p>スタッフ交代時はその場で別のスタッフが自分の PIN を入力するだけで OK（ログアウト不要）。</p><h3 id="_1-5-1-会計待ちテーブルを選ぶ" tabindex="-1">1-5-1. 会計待ちテーブルを選ぶ <a class="header-anchor" href="#_1-5-1-会計待ちテーブルを選ぶ" aria-label="Permalink to &quot;1-5-1. 会計待ちテーブルを選ぶ&quot;">​</a></h3><ol><li>POSレジ画面の <strong>左カラム</strong> に会計待ちテーブルが表示されている</li><li>お客様が会計したいテーブル（T03）のカードをタップ</li><li><strong>右カラム</strong> にそのテーブルの注文詳細（品目・金額）が表示される</li></ol><h3 id="_1-5-1-b-会計時に「-conflict-」「-already-paid-」が出たら-2026-04-19-s3-追加" tabindex="-1">1-5-1-b. 会計時に「[CONFLICT]」「[ALREADY_PAID]」が出たら（2026-04-19 S3 追加） <a class="header-anchor" href="#_1-5-1-b-会計時に「-conflict-」「-already-paid-」が出たら-2026-04-19-s3-追加" aria-label="Permalink to &quot;1-5-1-b. 会計時に「[CONFLICT]」「[ALREADY_PAID]」が出たら（2026-04-19 S3 追加）&quot;">​</a></h3><p>会計確定ボタンを押した後、画面に以下のいずれかが表示された場合の対処です。</p><table tabindex="0"><thead><tr><th>表示メッセージ</th><th>何が起きたか</th><th>対処</th></tr></thead><tbody><tr><td><code>[ALREADY_PAID]</code> または「すでに会計済みです」</td><td>別の端末（別のレジ・別のスタッフ・あるいは同じ端末で 2 回押した） が <strong>0.数秒前にすでに同じ伝票を会計済み</strong></td><td><strong>慌てず画面リロード</strong> → テーブルが空席になっていれば既に会計完了済み。<strong>重複課金は発生していません</strong></td></tr><tr><td><code>[CONFLICT]</code> または「処理が競合しました」</td><td>同時に別操作（例: 別端末で品目追加 + こちらで会計）が発生</td><td>画面リロード → 最新状態を確認 → 必要なら再会計</td></tr><tr><td><code>[AMOUNT_MISMATCH]</code></td><td>端末の表示金額とサーバー再計算金額が違う（直前にメニュー価格更新あり）</td><td>画面リロード → メニュー価格再取得 → 再会計</td></tr><tr><td><code>[STRIPE_MISMATCH]</code></td><td>Stripe Terminal の決済結果と DB 上の payment_intent が不一致</td><td>店長 → POSLA 運営に連絡（会計は中断）</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">なぜこの仕組みが入ったのか</p><ul><li>2026-04-19 のセキュリティ修正で、<strong>同時会計による二重課金を完全防止</strong> するためサーバー側で排他制御（BEGIN + SELECT FOR UPDATE）を入れました</li><li>そのため「先に押した人が勝ち、後から押した方は CONFLICT で弾かれる」挙動になります</li><li><strong>「お客様にカード決済が二重で走った？」と心配する必要はありません</strong>。CONFLICT が出たということは、サーバーが二重課金を未然に防いだ証拠です</li></ul></div><p>詳細は <a href="./../tenant/08-cashier.html#8152-会計処理">tenant 8 章 8.15.2 会計処理トラブル</a> と <a href="./../tenant/18-security.html#18w-s3-セキュリティ修正一式2026-04-19">tenant 18 章 18.W S3 セキュリティ修正一式</a> を参照。</p><hr><h3 id="_1-5-2-現金でのお会計手順" tabindex="-1">1-5-2. 現金でのお会計手順 <a class="header-anchor" href="#_1-5-2-現金でのお会計手順" aria-label="Permalink to &quot;1-5-2. 現金でのお会計手順&quot;">​</a></h3><ol><li><strong>右カラム</strong> の注文詳細の下にある支払方法選択で <strong>【現金】</strong> をタップ</li><li>画面に <strong>受取金額</strong> 入力欄が表示される</li><li>お客様から受け取った金額を <strong>テンキー</strong> で入力（例: ¥5,000）</li><li>画面下に <strong>合計金額</strong> と <strong>お釣り</strong> が自動計算される（例: 合計 ¥3,400、お釣り ¥1,600）</li><li><strong>【会計する】</strong> ボタン（緑色の大きなボタン）をタップ</li><li>確認ダイアログで <strong>【OK】</strong></li><li>レジが開く（プリンタが繋がっている場合、レシートが自動印刷される）</li><li>お客様にお釣り、レシートを渡す</li></ol><h3 id="_1-5-3-クレジットカードでのお会計手順" tabindex="-1">1-5-3. クレジットカードでのお会計手順 <a class="header-anchor" href="#_1-5-3-クレジットカードでのお会計手順" aria-label="Permalink to &quot;1-5-3. クレジットカードでのお会計手順&quot;">​</a></h3><p>Stripe Reader S700 が接続されている場合のみ。</p><ol><li>テーブルを選んで支払方法で <strong>【カード】</strong> をタップ</li><li><strong>【会計する】</strong> をタップ</li><li>S700 にお客様のカードをタッチ（非接触）または挿入</li><li>S700 画面に「処理中」表示</li><li>決済が承認されると「完了」表示</li><li>POSレジ画面に <strong>「決済完了」</strong> と表示</li><li>レシート自動印刷、お客様に渡す</li></ol><h3 id="_1-5-4-qr-決済-paypay、d払い等-でのお会計手順" tabindex="-1">1-5-4. QR 決済（PayPay、d払い等）でのお会計手順 <a class="header-anchor" href="#_1-5-4-qr-決済-paypay、d払い等-でのお会計手順" aria-label="Permalink to &quot;1-5-4. QR 決済（PayPay、d払い等）でのお会計手順&quot;">​</a></h3><ol><li>支払方法で <strong>【QR】</strong> を選択</li><li><strong>【会計する】</strong> をタップ</li><li>お客様がスマホで自店の PayPay 等の QR を読む</li><li>決済完了後、POSLA の「完了」ボタンを押して記録</li><li>レシート印刷</li></ol><h3 id="_1-5-5-セルフレジ-お客様がスマホで決済" tabindex="-1">1-5-5. セルフレジ（お客様がスマホで決済） <a class="header-anchor" href="#_1-5-5-セルフレジ-お客様がスマホで決済" aria-label="Permalink to &quot;1-5-5. セルフレジ（お客様がスマホで決済）&quot;">​</a></h3><p>お客様が自分のスマホから Stripe Checkout で決済する場合。</p><ol><li>お客様がメニュー画面の <strong>【お会計に進む】</strong> をタップ</li><li>Stripe のクレジットカード入力画面が開く</li><li>カード情報を入力して決済</li><li>決済完了後、自動でテーブルセッションがクリアされる</li><li>POSレジには通知が入らないので、テーブルが空いたらスタッフが物理確認</li></ol><h3 id="_1-5-6-個別会計-割り勘" tabindex="-1">1-5-6. 個別会計（割り勘） <a class="header-anchor" href="#_1-5-6-個別会計-割り勘" aria-label="Permalink to &quot;1-5-6. 個別会計（割り勘）&quot;">​</a></h3><p>「私のだけ別で払います」というケース。</p><ol><li>左カラムで該当テーブル選択</li><li>右カラムの注文品目リストで、<strong>個別会計したい品目だけ</strong> のチェックボックスを ON</li><li><strong>【会計する】</strong> で選択した品目だけ会計</li><li>残りの品目は後から別会計できる</li></ol><h3 id="_1-5-6-b-相席の別会計-サブセッション-f-qr1" tabindex="-1">1-5-6-b. 相席の別会計（サブセッション / F-QR1） <a class="header-anchor" href="#_1-5-6-b-相席の別会計-サブセッション-f-qr1" aria-label="Permalink to &quot;1-5-6-b. 相席の別会計（サブセッション / F-QR1）&quot;">​</a></h3><p>相席で別グループが別々に会計したい場合。ハンディで <strong>個別 QR</strong> を発行する仕組み。</p><h4 id="状況例" tabindex="-1">状況例 <a class="header-anchor" href="#状況例" aria-label="Permalink to &quot;状況例&quot;">​</a></h4><ul><li>T05 に Aグループ 2 名（既に着席・注文済）</li><li>後から B グループ 3 名が相席で着席（同じテーブル）</li><li>A / B で別々に会計したい</li></ul><h4 id="手順-7" tabindex="-1">手順 <a class="header-anchor" href="#手順-7" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>ハンディの <strong>【テーブル状況】</strong> タブを開く</li><li>T05 カードの <strong>【📟 個別QR】</strong>（オレンジボタン）をタップ</li><li>新しいサブセッション用 QR が発行される（画面表示 or 紙に印刷）</li><li>B グループにその QR を渡してスマホで読んでもらう</li><li>B グループは独立して注文可能</li><li>会計時は POSレジ側でサブセッション別に処理</li></ol><p>内部実装: <code>api/store/sub-sessions.php</code>、<code>orders.sub_session_id</code> に紐付け。詳細は <a href="./../tenant/05-tables.html">5 章 5.Y2</a> 参照。</p><h3 id="_1-5-7-レシート発行" tabindex="-1">1-5-7. レシート発行 <a class="header-anchor" href="#_1-5-7-レシート発行" aria-label="Permalink to &quot;1-5-7. レシート発行&quot;">​</a></h3><ul><li>自動印刷がデフォルト（プリンタ設定済みの場合）</li><li>手動再発行: <strong>取引履歴</strong> から該当取引を選んで <strong>【再発行】</strong></li></ul><hr><h2 id="_1-6-テイクアウト注文の処理" tabindex="-1">1-6. テイクアウト注文の処理 <a class="header-anchor" href="#_1-6-テイクアウト注文の処理" aria-label="Permalink to &quot;1-6. テイクアウト注文の処理&quot;">​</a></h2><h3 id="_1-6-1-オンラインテイクアウト注文の受付" tabindex="-1">1-6-1. オンラインテイクアウト注文の受付 <a class="header-anchor" href="#_1-6-1-オンラインテイクアウト注文の受付" aria-label="Permalink to &quot;1-6-1. オンラインテイクアウト注文の受付&quot;">​</a></h3><ol><li>お客様が店頭の <strong>テイクアウト QR</strong> を読む、または Google で店舗検索からテイクアウトページに入る</li><li>メニュー選択 → オンライン決済（Stripe）で前払い</li><li>注文が入ると POSLA 管理画面の <strong>「テイクアウト」</strong> タブに表示される</li><li>キッチンの KDS 画面にもテイクアウトバッジ付きで注文が出る</li></ol><h3 id="_1-6-2-受取時間のチェック" tabindex="-1">1-6-2. 受取時間のチェック <a class="header-anchor" href="#_1-6-2-受取時間のチェック" aria-label="Permalink to &quot;1-6-2. 受取時間のチェック&quot;">​</a></h3><ol><li>管理ダッシュボードの <strong>【テイクアウト】</strong> タブ</li><li>各注文の「受取予定時刻」を確認</li><li>受取 15 分前には完成するよう調理開始</li></ol><h3 id="_1-6-3-お客様が受け取りに来たら" tabindex="-1">1-6-3. お客様が受け取りに来たら <a class="header-anchor" href="#_1-6-3-お客様が受け取りに来たら" aria-label="Permalink to &quot;1-6-3. お客様が受け取りに来たら&quot;">​</a></h3><ol><li>【受取済み】ボタンをタップ</li><li>注文が完了状態になる</li></ol><hr><h2 id="_1-7-品切れの設定と解除" tabindex="-1">1-7. 品切れの設定と解除 <a class="header-anchor" href="#_1-7-品切れの設定と解除" aria-label="Permalink to &quot;1-7. 品切れの設定と解除&quot;">​</a></h2><p><strong>対象者</strong>: キッチンスタッフ / 店長</p><h3 id="品切れを設定する" tabindex="-1">品切れを設定する <a class="header-anchor" href="#品切れを設定する" aria-label="Permalink to &quot;品切れを設定する&quot;">​</a></h3><ol><li>KDS 画面の <strong>【品切れ管理】</strong> ボタン（画面右上あたり）をタップ</li><li>メニュー一覧が表示される</li><li>品切れになった品目の <strong>「品切れ」スイッチ</strong> を ON</li><li>すぐにセルフオーダー・ハンディ画面で品切れ表示になる</li></ol><h3 id="品切れを解除する" tabindex="-1">品切れを解除する <a class="header-anchor" href="#品切れを解除する" aria-label="Permalink to &quot;品切れを解除する&quot;">​</a></h3><ol><li>同じ画面で <strong>「品切れ」スイッチ</strong> を OFF</li><li>販売再開</li></ol><hr><h2 id="_1-8-ラストオーダーの設定" tabindex="-1">1-8. ラストオーダーの設定 <a class="header-anchor" href="#_1-8-ラストオーダーの設定" aria-label="Permalink to &quot;1-8. ラストオーダーの設定&quot;">​</a></h2><p>閉店時間前に「ラストオーダーです」とお知らせする設定。</p><ol><li>管理ダッシュボードの <strong>「店舗設定」→「店舗設定」</strong></li><li>営業基本設定の <strong>「ラストオーダー時刻」</strong> を入力（例: 21:30）</li><li>保存</li><li>21:30 以降、セルフオーダーの注文送信がブロックされる</li></ol><hr><h2 id="_1-9-閉店作業" tabindex="-1">1-9. 閉店作業 <a class="header-anchor" href="#_1-9-閉店作業" aria-label="Permalink to &quot;1-9. 閉店作業&quot;">​</a></h2><h3 id="_1-9-1-レジを閉める-レジ締め" tabindex="-1">1-9-1. レジを閉める（レジ締め） <a class="header-anchor" href="#_1-9-1-レジを閉める-レジ締め" aria-label="Permalink to &quot;1-9-1. レジを閉める（レジ締め）&quot;">​</a></h3><p>1 日の売上を締める操作です。</p><div class="warning custom-block"><p class="custom-block-title">レジ閉めにも担当スタッフ PIN が必須（CB1d、2026-04-19 追加）</p><p>レジ閉めも開け・入金・出金と同じく <strong>担当スタッフ PIN 入力が必須</strong>。退勤打刻する前に締めること（先に退勤打刻すると自分の PIN が無効化されて締められなくなる）。マネージャーも例外なし。</p></div><ol><li>POSレジ画面の右上 <strong>【💰 レジ開閉】</strong> をタップ</li><li><strong>【レジを閉める】</strong> パネル</li><li>「実際の現金額」欄にレジ内の現金を数えて入力（例: ¥48,500）</li><li><strong>【閉める】</strong> ボタン → <strong>担当スタッフ PIN 入力モーダル</strong>（CB1d）</li><li>自分の 4〜8 桁 PIN を入力 → <strong>【確定】</strong></li><li>画面に以下が表示される: <ul><li>開始時在高: ¥10,000</li><li>現金売上: ¥38,500</li><li>入金: ¥0</li><li>出金: ¥0</li><li><strong>予想在高</strong>: ¥48,500</li><li><strong>実際</strong>: ¥48,500</li><li><strong>差額</strong>: ¥0</li></ul></li><li>差額が 0 ならそのまま完了</li><li>差額が大きい（¥500 以上）場合は警告表示 → 現金を数え直す（監査ログに「誰が・いつ・差額いくらで締めたか」がすべて残るので、不一致の責任所在が後から追跡できます）</li><li>レジが締まり、営業終了</li></ol><h3 id="_1-9-2-売上の確認方法" tabindex="-1">1-9-2. 売上の確認方法 <a class="header-anchor" href="#_1-9-2-売上の確認方法" aria-label="Permalink to &quot;1-9-2. 売上の確認方法&quot;">​</a></h3><ol><li>管理ダッシュボードの <strong>【レポート】→【売上レポート】</strong></li><li>本日の売上、時間帯別、支払方法別、品目別の内訳が見られる</li></ol><h3 id="_1-9-3-kds-ハンディ-posレジのログアウト" tabindex="-1">1-9-3. KDS / ハンディ / POSレジのログアウト <a class="header-anchor" href="#_1-9-3-kds-ハンディ-posレジのログアウト" aria-label="Permalink to &quot;1-9-3. KDS / ハンディ / POSレジのログアウト&quot;">​</a></h3><p>人間スタッフが使うハンディは必ずログアウト。</p><ul><li><strong>個人スタッフアカウント</strong>（人間）は <strong>必ず退勤前にログアウト</strong></li><li><strong>デバイスアカウント</strong>（KDS-1 など）は <strong>ログアウト不要</strong>（常時ログインしっぱなしが前提）</li></ul><h4 id="ログアウト手順" tabindex="-1">ログアウト手順 <a class="header-anchor" href="#ログアウト手順" aria-label="Permalink to &quot;ログアウト手順&quot;">​</a></h4><ol><li>画面右上の <strong>【ログアウト】</strong> ボタンをタップ</li><li>ログイン画面に戻る</li></ol><h4 id="端末の電源" tabindex="-1">端末の電源 <a class="header-anchor" href="#端末の電源" aria-label="Permalink to &quot;端末の電源&quot;">​</a></h4><ul><li>次の日も使うなら <strong>電源は入れっぱなし</strong> でも OK（ロック画面にはなる）</li><li>省電力のため切りたいなら、電源ボタン長押しで電源オフ</li></ul><hr><h2 id="_1-10-よくある質問-part-1-向け" tabindex="-1">1-10. よくある質問（Part 1 向け） <a class="header-anchor" href="#_1-10-よくある質問-part-1-向け" aria-label="Permalink to &quot;1-10. よくある質問（Part 1 向け）&quot;">​</a></h2><p><strong>Q1. ハンディでの注文送信中に Wi-Fi が切れたら？</strong></p><p>A1. 送信が失敗してエラー表示になります。カートの内容は残るので、Wi-Fi が復旧したらそのまま再送信してください。</p><p><strong>Q2. 同じテーブルに追加で料理を頼まれた</strong></p><p>A2. ハンディの <strong>【店内注文】</strong> タブで、そのテーブルを選んで追加品目を送信すれば、既存注文に追加されます。</p><p><strong>Q3. お客様が注文を取り消したい</strong></p><p>A3. KDS 画面で該当注文の <strong>【取消】</strong> ボタンをタップ。キャンセルされます。既に会計済みの場合は 8 章「返金処理」を参照。</p><p><strong>Q4. テーブルを間違って選んで注文送信してしまった</strong></p><p>A4. ハンディの <strong>【注文履歴】</strong> タブから該当注文を探して <strong>【編集】</strong> → テーブルを修正。ただし会計済みは編集不可。</p><p><strong>Q5. 料理の提供を忘れて 20 分以上経ってしまった</strong></p><p>A5. KDS 画面で該当注文カードが赤く点滅しているはず。すぐ提供してお客様にお詫びください。自動で「遅延アラート」も POSLA 運営に通知されています。</p><hr><h2 id="_1-11-次のページへ" tabindex="-1">1-11. 次のページへ <a class="header-anchor" href="#_1-11-次のページへ" aria-label="Permalink to &quot;1-11. 次のページへ&quot;">​</a></h2><p>→ <a href="./part2-staff.html">Part 2: スタッフ管理</a></p>`,224)])])}const u=l(o,[["render",n]]);export{c as __pageData,u as default};
